record_types.code:
type Operation (Kind : Op_Kind := Op_Insert) is record
   Seq     : Natural;
   Node    : Core.Replica_Id;
   case Kind is
      when Op_Insert =>
         Position : Positive;
      when Op_Delete =>
         Del_Position : Positive;
      when Op_Increment | Op_Decrement =>
         Amount    : Natural;
         Actor     : Core.Replica_Id;
   end case;
end record;
